export function MovieProfile({ pictureUrl, releaseDate, title, overview }: MovieProfileProps) {
	const { language, theme } = useUserPreferences();
	return (
		 <div className={`${theme.lighterThemeBgClassName} ${theme.themeTextClassName} group hover:${theme.movieProfileHoverTheme} hover:scale-125 transition-transform rounded-lg flex flex-col text-center font-semibold p-4 self-auto align-middle`}>
			  <img className="mx-auto h-80 w-60 rounded-md" src={pictureUrl} alt={`Banner do Filme${title}`} />
			  <p>{title}</p>
			  <p className="font-nunito font-light">{LANGUAGES[language].releaseDate} {formatDate(language, releaseDate)}</p>
			  <p className="hidden group-hover:block font-light">Description: {overview}</p>
		 </div>
	);
}
